1	const BASE_PRICE_BY_TYPE: Record<string, number> = {
2	  potion: 40,
3	  amulet: 60,
4	  staff: 80,
5	  sword: 100,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	const RUNE_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
10	const RUNE_COMPONENT_BLOCK_SIZE = 3;
11	const RUNE_COMPONENT_BLOCK_PRICE = 60;
12	
13	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
14	const PROCESSING_FEE = 5;
15	
16	export function quote(input: { customer: { yearsWithMHPCO: number }; items: { type: string }[] }): number {
17	  const items = input.items;
18	  const countByType: Record<string, number> = {};
19	  for (const item of items) {
20	    countByType[item.type] = (countByType[item.type] ?? 0) + 1;
21	  }
22	  let basePrice = 0;
23	  for (const type of Object.keys(countByType)) {
24	    const count = countByType[type];
25	    const formsRuneBlock = RUNE_COMPONENT_TYPES.has(type) && count === RUNE_COMPONENT_BLOCK_SIZE;
26	    if (formsRuneBlock) {
27	      basePrice += RUNE_COMPONENT_BLOCK_PRICE;
28	    } else {
29	      basePrice += count * BASE_PRICE_BY_TYPE[type];
30	    }
31	  }
32	  const firstInsuranceSurcharge = basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
33	  const premium = basePrice + firstInsuranceSurcharge + PROCESSING_FEE;
34	  return Math.ceil(premium);
35	}
